/* PasstheEPPP — Question Bank Batch 18
   Enhanced rationale format — 80 new questions across all 8 domains */
(function(){
    if (typeof EPPPData === 'undefined') return;

    const batch18 = [
        // ===== Domain 1: Biological Bases (10) =====
        {domainId:1, q:"Phantom limb pain after amputation is best explained by:", options:["The explicit structural physical objective biological functional limb remains partially objectively present","Cortical reorganization — the brain's somatosensory map remaps the missing limb's territory to adjacent areas","A specifically entirely complex deeply rooted unconscious psychological systemic denial of the amputation","An exclusively localized profoundly severe explicit objective structural infection at the amputation site"], answer:1, difficulty:"hard", rationale:"Correct: (B) Ramachandran's research: after amputation, cortical areas mapped to the missing limb are 'invaded' by adjacent cortical representations. Touching the face may evoke sensation in the 'phantom' hand because face and hand areas are adjacent on the somatosensory cortex.\n\nWhy others are wrong:\n(A) The limb is completely absent — phantom sensations originate in the brain's cortical maps\n(C) Phantom limb is a neurological phenomenon, not psychological denial\n(D) Infection would cause local pain at the stump, not phantom sensations in the missing limb"},
        {domainId:1, q:"The substantia nigra is critical for:", options:["Specifically regulating complex explicit advanced linguistic grammar and language comprehension","Dopamine production and voluntary movement — its degeneration causes Parkinson's disease","Specifically regulating explicit advanced complex primary fundamental holistic visual processing","Specifically regulating explicit advanced complex primary long-term memory trace consolidation"], answer:1, difficulty:"medium", rationale:"Correct: (B) The substantia nigra (midbrain) produces dopamine via the nigrostriatal pathway to the basal ganglia, facilitating voluntary movement. Degeneration of substantia nigra dopaminergic neurons → Parkinson's disease (bradykinesia, rigidity, resting tremor).\n\nWhy others are wrong:\n(A) Language comprehension → Wernicke's area (left temporal lobe)\n(C) Visual processing → occipital lobe\n(D) Memory consolidation → hippocampus"},
        {domainId:1, q:"The action potential follows the:", options:["The explicitly broad highly specific fundamentally continuous proportional graded potential principle","All-or-none law — once threshold is reached, the neuron fires at full strength regardless of stimulus intensity","The explicitly broad highly specific fundamentally continuous proportional inverse square physical law","The explicitly broad highly specific fundamentally continuous proportional law of diminishing returns"], answer:1, difficulty:"easy", rationale:"Correct: (B) Action potentials are all-or-none: once the membrane potential reaches threshold (~-55mV), a full action potential occurs. Stimulus intensity is coded by FIRING RATE and NUMBER of neurons firing, not action potential magnitude.\n\nWhy others are wrong:\n(A) Graded potentials (EPSPs/IPSPs) vary in magnitude — action potentials do not (they're all-or-none)\n(C) The inverse square law applies to physics (light, gravity), not neuronal firing\n(D) Law of diminishing returns is an economics principle, not a neuroscience concept"},
        {domainId:1, q:"Chronic traumatic encephalopathy (CTE) is associated with:", options:["A specifically isolated distinctly standard explicitly recognized severe single head concussion","Repeated head impacts, causing accumulation of tau protein and progressive neurodegeneration","An explicitly standard universally expected entirely ubiquitous predictable normal aging process","An explicitly distinct uniquely severe formally recognized persistent chronic vitamin deficiency"], answer:1, difficulty:"medium", rationale:"Correct: (B) CTE results from repeated traumatic brain injuries (common in contact sports, military). Key pathology: abnormal tau protein accumulation (neurofibrillary tangles). Symptoms: mood/behavior changes, cognitive decline, dementia.\n\nWhy others are wrong:\n(A) A single concussion typically doesn't cause CTE — it's the REPEATED impacts that drive the pathology\n(C) CTE is a pathological condition from head trauma, not a normal aging process\n(D) Vitamin deficiency causes different conditions (B1 → Wernicke-Korsakoff; B12 → neuropathy)"},
        {domainId:1, q:"The ventricles of the brain contain:", options:["Circulating arterial blood","Cerebrospinal fluid (CSF)","Densely packed neurons","Myelinated white matter"], answer:1, difficulty:"easy", rationale:"Correct: (B) The four ventricles (two lateral, third, fourth) contain CSF, which cushions the brain, removes waste, delivers nutrients, and maintains intracranial pressure. CSF is produced by the choroid plexus.\n\nWhy others are wrong:\n(A) Blood flows through arteries, veins, and capillaries — not through the ventricles\n(C) Neurons are located in cortical and subcortical gray matter, not in the ventricles\n(D) White matter tracts run through brain parenchyma, not ventricles"},
        {domainId:1, q:"Acetylcholine is important for:", options:["Exclusively distinctly directly driving only rigorous skeletal muscle contraction","Memory, learning, muscle contraction, and parasympathetic nervous system function","Exclusively distinctly directly driving only rigorous circadian sleep regulation","Exclusively distinctly directly driving only rigorous generalized pain perception"], answer:1, difficulty:"medium", rationale:"Correct: (B) Acetylcholine (ACh) has diverse roles: neuromuscular junction (muscle contraction), parasympathetic NS (rest/digest), basal forebrain → cortex (attention, memory, learning). ACh depletion in Alzheimer's disease contributes to cognitive decline.\n\nWhy others are wrong:\n(A) ACh has CNS functions (memory, learning) in addition to peripheral neuromuscular roles\n(C) While ACh modulates sleep-wake cycles, it has many other functions\n(D) ACh is not primarily a pain-processing neurotransmitter"},
        {domainId:1, q:"Functional connectivity in neuroimaging refers to:", options:["Direct observable explicitly continuous primary physical white matter anatomical tract connections","Statistical correlations in brain activity between regions that may not be directly anatomically connected","Strictly exclusively explicitly objectively purely mathematically exclusively measuring blood flow","Strictly exclusively explicitly objectively purely mathematically isolating specific electrical activity"], answer:1, difficulty:"hard", rationale:"Correct: (B) Functional connectivity identifies brain regions whose activity patterns are temporally correlated (co-activate together). This reveals neural networks without requiring direct anatomical connections. Used extensively in resting-state fMRI research.\n\nWhy others are wrong:\n(A) Physical white matter connections = structural/anatomical connectivity (measured with DTI), not functional\n(C) Functional connectivity can be measured using fMRI (blood flow), EEG (electrical), or other modalities\n(D) Multiple imaging modalities can assess functional connectivity, not just EEG"},
        {domainId:1, q:"Anosognosia refers to:", options:["A profound structural complete bilateral diagnostic objective loss of smell","Lack of awareness or denial of one's own neurological deficit or illness","A profound complete biological objective highly specific fear of spiders","A profound complete cognitive biological objective difficulty with arithmetic"], answer:1, difficulty:"hard", rationale:"Correct: (B) Anosognosia: impaired awareness of one's own disability (e.g., a stroke patient denying paralysis of their left arm). Commonly seen with right parietal lesions. Distinct from psychological denial — it has a neurological basis.\n\nWhy others are wrong:\n(A) Loss of smell = anosmia, not anosognosia\n(C) Fear of spiders = arachnophobia\n(D) Difficulty with arithmetic = dyscalculia or acalculia"},
        {domainId:1, q:"Sensitization is a form of non-associative learning in which:", options:["A highly specific repeated consistent exposure strictly decreases any response","A single strong stimulus leads to an INCREASED response to subsequent stimuli","Two highly distinct specific biological stimuli are definitively paired together","A highly distinct specific biological behavior is definitively fully reinforced"], answer:1, difficulty:"medium", rationale:"Correct: (B) Sensitization: after an intense or noxious stimulus, subsequent responses to even mild stimuli are amplified. Example: after a loud bang, you startle more easily to minor sounds. Opposite of habituation.\n\nWhy others are wrong:\n(A) Decreased response to repeated exposure = habituation (the opposite)\n(C) Pairing stimuli = associative learning (classical conditioning), not sensitization\n(D) Reinforcement = operant conditioning (associative), not non-associative sensitization"},
        {domainId:1, q:"The blood alcohol concentration (BAC) that legally defines intoxication in most U.S. states is:", options:[".02%",".05%",".08%",".15%"], answer:2, difficulty:"easy", rationale:"Correct: (C) The legal BAC limit for driving in all 50 U.S. states is .08%. Cognitive and motor impairment begins at much lower levels. For commercial drivers, the limit is .04%; for those under 21, zero tolerance (typically .02%).\n\nWhy others are wrong:\n(A) .02% is below the standard legal limit (used for zero-tolerance underage laws)\n(B) .05% is below the standard legal limit (though some countries use this standard)\n(D) .15% is nearly double the legal limit and would indicate severe intoxication"},

        // ===== Domain 2: Cognitive-Affective (10) =====
        {domainId:2, q:"Schemas (Bartlett) influence memory by:", options:["Specifically guaranteeing explicitly perfect structural consistent accurate profoundly formal reliable objective memory recall","Guiding encoding and retrieval, leading to both efficient processing and systematic distortions that fit existing knowledge structures","Demonstrating absolutely minimal measurable observable tangible practical direct functional effect upon general memory recall","Exclusively specifically selectively influencing only deeply established formally rigid active procedural motor memory systems"], answer:1, difficulty:"medium", rationale:"Correct: (B) Bartlett (Remembering, 1932): schemas help us process and organize information efficiently but also cause distortions — we fill in gaps with schema-consistent information and distort memories to match expectations.\n\nWhy others are wrong:\n(A) Schemas cause systematic distortions — they don't ensure perfect recall\n(C) Schemas profoundly affect what we attend to, encode, and retrieve\n(D) Schemas primarily affect DECLARATIVE memory (semantic and episodic), not just procedural"},
        {domainId:2, q:"The generation effect demonstrates that:", options:["Passive reading definitively routinely systematically explicitly proves functionally superior to active generation","Actively generating information (e.g., completing word fragments) produces better memory than passively reading it","The specific complex cognitive constructive process of memory generation remains completely physiologically impossible","Strictly exclusively precisely identifying this exact cognitive effect solely within visual processing modalities"], answer:1, difficulty:"medium", rationale:"Correct: (B) The generation effect: when learners actively produce information (fill in blanks, generate answers) rather than simply reading it, retention is significantly stronger. Supports active learning pedagogies.\n\nWhy others are wrong:\n(A) Passive reading is INFERIOR — the generation effect specifically demonstrates active generation's superiority\n(C) Memory generation is very much possible and beneficial\n(D) The generation effect applies across verbal, visual, and other modalities"},
        {domainId:2, q:"Learned helplessness (Seligman) occurs when:", options:["Organisms consistently successfully explicitly learn to actively deliberately rapidly escape all severe aversive situations","Organisms exposed to uncontrollable aversive events learn their actions are futile and stop trying despite possible escape","Organisms paradoxically consistently systematically become significantly profoundly more motivated following distinct failure","The expressed pervasive deep psychological helplessness is always strictly inherently purely fundamentally innately biological"], answer:1, difficulty:"medium", rationale:"Correct: (B) Seligman & Maier: dogs exposed to inescapable shocks later failed to escape when escape was possible. Extended to human depression: belief that outcomes are uncontrollable leads to motivational, cognitive, and emotional deficits.\n\nWhy others are wrong:\n(A) Active escape = normal learning; learned helplessness is the FAILURE to escape\n(C) Learned helplessness produces DECREASED motivation, not increased motivation after failure\n(D) Learned helplessness is LEARNED through experience with uncontrollable events, not innate"},
        {domainId:2, q:"The Zeigarnik effect refers to:", options:["Systematically forgetting formally successfully completed routine required tasks","Better memory for INCOMPLETE or interrupted tasks than for completed ones","Consistently meticulously always finishing required specific tasks to completion","Significant robust memory improvement occurring exclusively primarily during sleep"], answer:1, difficulty:"hard", rationale:"Correct: (B) Zeigarnik (1927): uncompleted tasks create a state of cognitive tension that keeps them more accessible in memory. Once completed, the tension resolves and the memory becomes less accessible.\n\nWhy others are wrong:\n(A) COMPLETED tasks are actually remembered LESS well than interrupted ones\n(C) The effect is about MEMORY for interruptions, not always completing tasks\n(D) Sleep-related memory consolidation is a separate phenomenon"},
        {domainId:2, q:"Functional fixedness prevents people from:", options:["Successfully explicitly utilizing standard typical objects strictly in conventional ways","Seeing objects as usable in novel, unconventional ways beyond their typical function","Successfully explicitly solving highly fundamental basic simple systematic daily problems","Successfully exploring formal manual physical objective tools within any functional capacity"], answer:1, difficulty:"medium", rationale:"Correct: (B) Functional fixedness (Duncker): a cognitive bias where people see objects only in their conventional use, failing to recognize alternative uses. The classic example: not seeing a box of tacks as a potential candle shelf.\n\nWhy others are wrong:\n(A) People CAN use objects conventionally — the fixedness LIMITS them to conventional uses\n(C) Functional fixedness specifically impairs CREATIVE problem-solving, not all problem types\n(D) People can use tools — they just have difficulty using them in novel ways"},
        {domainId:2, q:"Intrinsic motivation (Deci & Ryan) is enhanced by satisfaction of:", options:["Strictly fundamental absolute monetary needs","Autonomy, competence, and relatedness needs","Strictly intense absolute competitive needs","Strictly specific basic external approval"], answer:1, difficulty:"medium", rationale:"Correct: (B) Self-determination theory (SDT): intrinsic motivation flourishes when three basic psychological needs are met — autonomy (sense of choice/control), competence (feeling effective), and relatedness (connection to others).\n\nWhy others are wrong:\n(A) Monetary rewards are EXTRINSIC and can actually UNDERMINE intrinsic motivation (overjustification effect)\n(C) Competition can UNDERMINE intrinsic motivation if it reduces autonomy and competence perceptions\n(D) External approval is an extrinsic motivator — SDT emphasizes internal satisfaction of basic needs"},
        {domainId:2, q:"The cocktail party effect demonstrates:", options:["That neurotypical people strictly objectively consistently biologically entirely cannot filter complex auditory information","Selective attention: the ability to focus on one conversation while detecting personally relevant stimuli in unattended channels","That all incoming complex environmental active auditory information is explicitly uniformly equivalently fully processed","That chaotic crowded social cocktail parties strictly definitively permanently broadly severely impair basic human cognition"], answer:1, difficulty:"easy", rationale:"Correct: (B) Cherry's cocktail party effect: we selectively attend to one auditory stream while suppressing others, but highly salient stimuli (our name, danger signals) in unattended channels can 'break through' the attentional filter.\n\nWhy others are wrong:\n(A) People CAN and DO filter auditory information effectively — that's the demonstration\n(C) Unattended information receives minimal processing — only salient items break through\n(D) The effect demonstrates normal cognitive filtering ability, not impairment"},
        {domainId:2, q:"Dunning-Kruger effect describes:", options:["Highly proficient specialized trained experts dramatically systematically overestimating their own cognitive abilities","Low-ability individuals overestimating their competence, while high-ability individuals slightly underestimate theirs","Everyone uniformly consistently accurately assessing their own explicit precise specific actual cognitive abilities","A unique distinct psychological heuristic explicitly practically applying exclusively isolated to academic settings"], answer:1, difficulty:"medium", rationale:"Correct: (B) Dunning-Kruger: people with limited knowledge/skill lack the metacognitive ability to recognize their incompetence, leading to inflated self-assessments. Experts, conversely, assume others share their knowledge level and slightly underestimate their relative standing.\n\nWhy others are wrong:\n(A) Experts tend to slightly UNDERESTIMATE their relative abilities, not overestimate\n(C) The effect specifically demonstrates systematic INACCURACY in self-assessment\n(D) The effect applies across domains (driving, grammar, logic, medicine, etc.), not just academics"},
        {domainId:2, q:"Mood-congruent memory refers to:", options:["Specific powerful memories robustly explicitly altering an individual's immediate active mood","The distinct tendency to constantly recall memories that match one's current emotional state","Exclusively distinctly reliably remembering solely objective profoundly positive historic events","Specific explicit objective autobiographical memories that are universally consistently accurate"], answer:1, difficulty:"easy", rationale:"Correct: (B) Mood-congruent memory: current mood facilitates retrieval of memories with matching emotional valence. When sad, negative memories are more accessible; when happy, positive memories are more accessible. Contributes to depression maintenance.\n\nWhy others are wrong:\n(A) Mood-congruent memory is about mood FACILITATING recall of matching memories, not memories changing mood\n(C) Any mood state (positive, negative, neutral) can facilitate mood-congruent recall\n(D) Mood-congruent recall doesn't guarantee accuracy — it's about emotional matching, not truth"},
        {domainId:2, q:"Inattentional blindness (Simons & Chabris) demonstrates that:", options:["Neurotypical people always explicitly accurately efficiently notice everything in their visual field","People can fail to notice salient, unexpected stimuli when attention is focused on another task","Recognized functional clinical blindness is strictly exclusively biologically distinctly physical","Human cognitive functional attention has biologically structurally infinitely unlimited capacity"], answer:1, difficulty:"easy", rationale:"Correct: (B) The 'invisible gorilla' study: participants counting basketball passes completely missed a person in a gorilla suit walking through the scene. Demonstrates that focused attention creates blindness to unattended stimuli.\n\nWhy others are wrong:\n(A) The study shows people MISS highly visible stimuli when attention is engaged elsewhere\n(C) Inattentional blindness is a perceptual/attentional phenomenon, not physical blindness\n(D) Attention has LIMITED capacity — that's precisely why inattentional blindness occurs"},

        // ===== Domain 4: Growth & Lifespan (10) =====
        {domainId:4, q:"Secure attachment (Ainsworth Type B) is characterized by:", options:["Persistent explicit indifference to the primary caregiver's consistent daily departure and subsequent return","Distress at separation, comfort-seeking at reunion, and using the caregiver as a secure base for exploration","Extreme pervasive anxious relational infant clinginess with absolutely no independent active exploration","Profoundly disorganized, contradictory, explicitly unpredictable, and highly chaotic relational behaviors"], answer:1, difficulty:"easy", rationale:"Correct: (B) Securely attached infants (~60-65%): explore freely using caregiver as secure base, show distress at separation but are quickly soothed at reunion, and prefer caregiver over stranger.\n\nWhy others are wrong:\n(A) Indifference to separation/reunion = avoidant attachment (Type A)\n(C) Extreme clinginess without exploration = resistant/ambivalent attachment (Type C)\n(D) Disorganized, contradictory behaviors = disorganized attachment (Type D)"},
        {domainId:4, q:"Kohlberg's conventional level of moral reasoning includes:", options:["Stage 1 (obedience/punishment orientation, emphasizing rigid compliance)","Stages 3 and 4 (interpersonal conformity and maintaining social order)","Stage 5 (social contract orientation, emphasizing relative broad rights)","Stage 6 (universal ethical principles, emphasizing internalized justice)"], answer:1, difficulty:"medium", rationale:"Correct: (B) Conventional level: Stage 3 (good boy/nice girl — maintaining relationships and approval) and Stage 4 (law and order — maintaining social systems and rules). Most adolescents and adults reason at this level.\n\nWhy others are wrong:\n(A) Stage 1 = preconventional level (morality based on punishment avoidance)\n(C) Stage 5 = postconventional level (social contract and individual rights)\n(D) Stage 6 = postconventional level (universal ethical principles — very rare)"},
        {domainId:4, q:"The 'still face' paradigm (Tronick) demonstrates:", options:["Infants fundamentally lack the developmental cognitive active capacity to reliably notice subtle complex underlying caregiver emotions","Infants are highly sensitive to caregiver emotions — becoming distressed and trying to re-engage when caregivers show a still face","Infants consistently systematically demonstrate a fundamentally profound distinct preference for unfamiliar novel adult strangers","Infants definitively intrinsically lack any biological structural capability to independently regulate internal affective emotions"], answer:1, difficulty:"medium", rationale:"Correct: (B) Tronick's still face: when caregivers suddenly become emotionally unresponsive (blank face), infants initially try to re-engage (smiling, vocalizing), then become distressed (crying, gaze aversion). Demonstrates infants' sensitivity to social reciprocity.\n\nWhy others are wrong:\n(A) Infants CLEARLY notice and are disturbed by caregiver emotional unavailability\n(C) Infants show strong preference for their caregiver — distress at caregiver unresponsiveness proves this\n(D) Infants DO attempt to regulate — they try to re-engage before becoming overwhelmed"},
        {domainId:4, q:"Fluid intelligence (Gf) typically:", options:["Consistently increases throughout the entire lifespan","Peaks in early adulthood and gradually declines with age","Demonstrates absolutely no relation to cognitive skills","Always comprehensively remains perfectly globally stable"], answer:1, difficulty:"medium", rationale:"Correct: (B) Cattell/Horn: fluid intelligence (novel reasoning, abstract problem-solving, pattern recognition) peaks around ages 20-30 and gradually declines. This is related to processing speed and working memory decline.\n\nWhy others are wrong:\n(A) Crystallized intelligence increases throughout life — fluid intelligence declines\n(C) Gf is strongly related to cognitive performance, especially on novel tasks\n(D) Gf is one of the cognitive abilities MOST affected by aging — it doesn't remain stable"},
        {domainId:4, q:"The rooting reflex in newborns:", options:["Represents a distinctly voluntary strictly explicitly learned cognitive developmental behavior","Is an innate reflex where the infant turns toward a touch on the cheek, facilitating breastfeeding","Consistently uniquely emerges strictly during the specific typical developmental milestone at age 2","Fundamentally serves as a reliable clinical indicator of specific severe neurological brain damage"], answer:1, difficulty:"easy", rationale:"Correct: (B) Rooting: when the newborn's cheek is touched, they turn toward the stimulus and open their mouth, facilitating finding the nipple for feeding. Present at birth, disappears around 3-4 months as voluntary feeding develops.\n\nWhy others are wrong:\n(A) Rooting is INNATE/reflexive, not learned — it's present from birth\n(C) Rooting is present at BIRTH and typically disappears by 3-4 months\n(D) Rooting is a NORMAL reflex — its ABSENCE would suggest neurological concern"},
        {domainId:4, q:"Authoritarian parenting (Baumrind) is characterized by:", options:["High emotional warmth and high firm demands","Low warmth, high demands and strict control","High emotional warmth alongside low demands","Low overall warmth accompanied by low demands"], answer:1, difficulty:"easy", rationale:"Correct: (B) Authoritarian parents are demanding and controlling but low in warmth/responsiveness. They expect obedience without explanation ('Because I said so'), use punishment, and value conformity over autonomy.\n\nWhy others are wrong:\n(A) High warmth + high demands = authoritative parenting (the optimal style)\n(C) High warmth + low demands = permissive/indulgent parenting\n(D) Low warmth + low demands = uninvolved/neglectful parenting"},
        {domainId:4, q:"Conservation tasks (Piaget) assess whether children understand that:", options:["Precious natural global resources should be actively preserved","Quantity remains the same despite changes in appearance/shape","Complex factual information should be fully stored permanently","Biological physical energy cannot be fully created or destroyed"], answer:1, difficulty:"easy", rationale:"Correct: (B) Piaget's conservation: understanding that quantity (number, mass, volume, liquid) is unchanged by superficial transformations (pouring into different-shaped containers, rearranging objects). Achieved in concrete operational stage (~7).\n\nWhy others are wrong:\n(A) Environmental conservation is a different meaning of the word — Piaget's concept is about cognitive understanding\n(C) Information storage = memory concepts, not Piagetian conservation\n(D) Energy conservation is a physics law, not a developmental psychology concept"},
        {domainId:4, q:"Preterm birth is defined as delivery before:", options:["34 weeks gestation","37 weeks gestation","40 weeks gestation","42 weeks gestation"], answer:1, difficulty:"easy", rationale:"Correct: (B) Preterm birth: delivery before 37 completed weeks of gestation. Full-term = 39-40 weeks. Risk factors: maternal stress, infection, multiple gestation, substance use. Outcomes depend on gestational age and birth weight.\n\nWhy others are wrong:\n(A) Before 34 weeks is 'late preterm' — preterm is defined from 37 weeks\n(C) 40 weeks = average full-term pregnancy duration\n(D) 42 weeks = post-term, which carries its own risks"},
        {domainId:4, q:"The socioemotional selectivity theory (Carstensen) proposes that:", options:["Aging older adults systematically demonstrate significantly reduced fundamental care regarding intimate interpersonal relationships","As time perspective shortens with age, people prioritize emotionally meaningful relationships and goals over information-seeking","Aging older adults systematically explicitly prioritize establishing completely novel distinct superficial social acquaintances","Chronological biological age continually exerts absolutely zero distinct measurable impact upon overall social preferences"], answer:1, difficulty:"medium", rationale:"Correct: (B) Carstensen: when people perceive time as limited (not just in old age — also terminal illness, relocating), they prioritize emotional meaning over novelty or information acquisition. This explains older adults' smaller but more satisfying social networks.\n\nWhy others are wrong:\n(A) Older adults care DEEPLY about relationships — they're more selective, not less caring\n(C) Older adults tend to prefer familiar, emotionally close relationships over new acquaintances\n(D) Age significantly affects social goals and partner preferences"},
        {domainId:4, q:"Transitive inference (Piaget) is achieved during:", options:["Primary sensorimotor stage","Early preoperational stage","Concrete operational stage","Innate presence from birth"], answer:2, difficulty:"medium", rationale:"Correct: (C) Transitive inference (if A > B and B > C, then A > C) requires logical-relational reasoning achieved in the concrete operational stage (~7-11). Preoperational children cannot perform this systematic comparison.\n\nWhy others are wrong:\n(A) Sensorimotor infants haven't developed logical operations\n(B) Preoperational children lack the logical reasoning for transitive inference\n(D) Transitive inference develops through cognitive maturation — it's not present at birth"},


        // ===== Domain 5: Assessment (5) =====
        {domainId:5, q:"The MCMI-IV (Millon Clinical Multiaxial Inventory) is specifically designed to assess:", options:["Core fluid and crystallized intelligence along with specific cognitive abilities","Personality disorders and clinical syndromes aligned with DSM-5/Millon's theory","Academic achievement and specific learning disabilities across objective domains","Adaptive behavior and essential objective independent daily living life skills"], answer:1, difficulty:"medium", rationale:"Correct: (B) The MCMI-IV (Millon, 2015) is a 195-item self-report inventory specifically designed to assess personality pathology and clinical syndromes. Scales align with DSM-5 personality disorders and Millon's evolutionary personality theory.\n\nWhy others are wrong:\n(A) Intelligence → WAIS-IV/V, WISC-V\n(C) Academic achievement → WJ-IV, WIAT-4\n(D) Adaptive behavior → Vineland-3, ABAS-3"},
        {domainId:5, q:"Percentile rank of 84 means:", options:["The individual only correctly answered precisely 84 explicit specific test items","The person scored equal to or better than 84% of the normative sample","The examinee performed abysmally entirely failing the standardized assessment","The raw standard score exactly inherently perfectly corresponds to an IQ of 84"], answer:1, difficulty:"easy", rationale:"Correct: (B) A percentile rank of 84 means the individual scored at or above 84% of the comparison group. It describes RELATIVE standing, not percentage correct. Note: 84th percentile ≈ 1 SD above the mean in a normal distribution.\n\nWhy others are wrong:\n(A) Percentile rank ≠ percentage correct or raw score\n(C) 84th percentile is above average — it doesn't indicate failure\n(D) An IQ of 84 corresponds to approximately the 14th percentile (1 SD below mean), not the 84th percentile"},
        {domainId:5, q:"Face validity refers to:", options:["Whether the standardized operational test accurately measures what it truly claims","Whether the test APPEARS to measure what it claims, based on surface-level judgment","Rigorous substantial advanced empirical statistical correlation with a valid criterion","Complex multidimensional specific underlying internal empirical factor analytic structure"], answer:1, difficulty:"easy", rationale:"Correct: (B) Face validity: the extent to which a test LOOKS like it measures what it intends to. It's the weakest form of validity but affects test-taker cooperation, engagement, and perceived fairness.\n\nWhy others are wrong:\n(A) WHETHER the test actually measures what it claims = construct validity (much stronger)\n(C) Statistical criterion correlation = criterion-related validity (concurrent or predictive)\n(D) Factor analysis = construct validity evidence (internal structure)"},
        {domainId:5, q:"Inter-rater reliability is assessed by:", options:["Comparing explicitly standard distinct clinical scores from two administrations over time","Having two or more raters independently score the same responses and comparing their agreement","Dividing a single composite test specifically sequentially exactly into two equal halves","Statistically significantly continually correlating against an explicit external criterion"], answer:1, difficulty:"easy", rationale:"Correct: (B) Inter-rater (inter-scorer) reliability: the degree of agreement between independent raters scoring the same responses. Measured using Cohen's kappa (categorical) or intraclass correlation (continuous). Critical for subjective scoring (essays, behavioral observations).\n\nWhy others are wrong:\n(A) Two administrations over time = test-retest reliability\n(C) Two halves = split-half reliability\n(D) External criterion correlation = criterion-related validity"},
        {domainId:5, q:"A stanine score of 5 indicates:", options:["Clearly significantly strictly profoundly below highly standard expected average performance","Average performance (the middle stanine)","Clearly explicitly routinely reliably achieving remarkably above standard average performance","Demonstrating obtaining specifically achieving the absolute explicitly highest possible score"], answer:1, difficulty:"medium", rationale:"Correct: (B) Stanines (standard nines): 1-9 scale, M = 5, SD ≈ 2. Stanine 5 = average/middle band (40th-60th percentile). Stanines 1-3 = below average; 4-6 = average; 7-9 = above average.\n\nWhy others are wrong:\n(A) Below average = stanines 1-3\n(C) Above average = stanines 7-9\n(D) The highest stanine = 9, not 5"},

        // ===== Domain 6: Treatment (5) =====
        {domainId:6, q:"Acceptance and Commitment Therapy (ACT) emphasizes:", options:["Systematically entirely eliminating all deeply entrenched negative psychological cognitive distressing internal thoughts","Psychological flexibility through acceptance of difficult experiences, mindfulness, and committed action toward values","Exclusively strictly implementing solely rigid objective behavioral techniques directed at overt habituation conditioning","Strictly enforcing standard cognitive restructuring protocols designed specifically entirely for rational reality testing"], answer:1, difficulty:"medium", rationale:"Correct: (B) ACT (Hayes): six core processes — acceptance, cognitive defusion, present moment awareness, self-as-context, values clarification, and committed action. The goal is psychological flexibility, NOT symptom elimination.\n\nWhy others are wrong:\n(A) ACT specifically does NOT try to eliminate negative thoughts — it promotes a changed RELATIONSHIP with them (defusion)\n(C) ACT integrates behavioral AND acceptance/mindfulness components\n(D) ACT uses cognitive DEFUSION (letting go of literal belief in thoughts) rather than traditional restructuring"},
        {domainId:6, q:"Strategic family therapy (Haley) uses:", options:["Exclusively gentle emotionally unstructured reflective active listening applied during family sessions","Directives, paradoxical interventions, and tasks designed to change dysfunctional interaction patterns","Profound extensive psychodynamic unconscious psychoanalytic interpretations of early childhood trauma","Strictly isolated exclusive individual therapy sessions ignoring broader functional family dynamics"], answer:1, difficulty:"medium", rationale:"Correct: (B) Haley's strategic therapy: therapist takes an active, directive role designing interventions (homework tasks, paradoxical directives, reframing, ordeal therapy) to disrupt dysfunctional family interaction sequences.\n\nWhy others are wrong:\n(A) Reflective listening = person-centered (Rogers); strategic therapy is highly directive\n(C) Psychoanalytic interpretation = psychodynamic approach, not strategic\n(D) Strategic therapy works with the FAMILY system, not just individuals"},
        {domainId:6, q:"Contingency management uses:", options:["Specific subjective complex psychoanalytic highly intensive formal dream analysis resolving the unconscious","Tangible reinforcers (vouchers, prizes) contingent on verified behavioral change (e.g., negative drug tests)","Highly unstructured spontaneous unrestricted free association fundamentally focused on latent core meaning","Formal intensive specific clinical psychodynamic analysis and strict interpretation of relational transference"], answer:1, difficulty:"easy", rationale:"Correct: (B) Contingency management: evidence-based behavioral approach using reinforcement (vouchers exchangeable for goods, prize drawings) contingent on objective verification of target behaviors (clean urine samples, treatment attendance).\n\nWhy others are wrong:\n(A) Dream analysis = psychoanalytic technique\n(C) Free association = psychoanalytic technique\n(D) Transference interpretation = psychoanalytic technique"},
        {domainId:6, q:"The miracle question in SFBT asks clients:", options:["To specifically vividly explicitly describe their absolute worst nightmare","To imagine waking up and the problem is solved — what would be different?","To exhaustively fundamentally analyze profoundly damaging childhood trauma","To systematically distinctly identify deep internal cognitive distortions"], answer:1, difficulty:"easy", rationale:"Correct: (B) The miracle question (de Shazer): 'Suppose tonight while you sleep a miracle happens and the problem is solved. When you wake up, how would you know? What would be different?' This shifts focus from problems to desired outcomes.\n\nWhy others are wrong:\n(A) Describing nightmares = might occur in trauma therapy, not SFBT\n(C) Childhood trauma analysis = psychodynamic approach; SFBT is future/solution-focused\n(D) Identifying cognitive distortions = CBT technique, not SFBT"},
        {domainId:6, q:"Pharmacotherapy for ADHD in children typically involves:", options:["Potent major atypical antipsychotic medications prioritizing dopamine blockade","Stimulant medications (methylphenidate, amphetamine) as first-line treatment","Sedating anxiolytic benzodiazepines prescribed exclusively for severe anxiety","Strictly regulated complex MAOI antidepressants carrying high dietary warnings"], answer:1, difficulty:"easy", rationale:"Correct: (B) Stimulants (methylphenidate/Ritalin, amphetamine/Adderall) are first-line for ADHD. They increase dopamine and norepinephrine availability, paradoxically improving focus and reducing hyperactivity/impulsivity.\n\nWhy others are wrong:\n(A) Antipsychotics are not first-line for ADHD (though sometimes used for severe aggression)\n(C) Benzodiazepines treat anxiety, not ADHD — they could worsen ADHD symptoms\n(D) MAOIs are rarely used for ADHD due to dietary restrictions and side effect profile"},

        // ===== Domain 7: Research (5) =====
        {domainId:7, q:"A correlation coefficient of r = -.85 indicates:", options:["A distinctly weak positive relationship where variables systematically increase together","A strong NEGATIVE relationship — as one variable increases, the other tends to decrease","Absolutely no distinct measurable statistical relationship between the specific variables","A specifically perfect positive relationship where both variables rigidly align together"], answer:1, difficulty:"easy", rationale:"Correct: (B) r = -.85 indicates a strong inverse relationship. The sign (negative) indicates direction (inverse); the absolute value (.85) indicates strength (strong). Correlation strength: .10 small, .30 medium, .50+ large.\n\nWhy others are wrong:\n(A) The relationship is NEGATIVE and STRONG, not weak and positive\n(C) r = 0 indicates no relationship; -.85 is far from zero\n(D) r = +1.0 indicates a perfect positive relationship; -.85 is negative"},
        {domainId:7, q:"Regression analysis allows researchers to:", options:["Exclusively summarize specifically defined categorical data without precise predictions","Predict the value of a dependent variable based on one or more independent variables","Definitively unequivocally specifically firmly establish exact causation with certainty","Exclusively distinctly specifically objectively simply statistically compare group means"], answer:1, difficulty:"medium", rationale:"Correct: (B) Regression: models the relationship between predictor(s) and an outcome variable, generating an equation to predict DV values from IV values. Simple regression uses one predictor; multiple regression uses two or more.\n\nWhy others are wrong:\n(A) Regression PREDICTS outcomes, going beyond mere description\n(C) Regression shows prediction/association but doesn't establish causation without experimental design\n(D) Comparing group means = ANOVA/t-test; regression examines continuous predictive relationships"},
        {domainId:7, q:"The Hawthorne effect refers to:", options:["Participants changing behavior knowing they are being observed or receiving attention","Subconscious profound explicit exact statistical subjective active experimenter bias","Gradual distinct completely normal standard explicit psychological natural maturation","Specific cognitive robust practice testing effects resulting from prior task exposure"], answer:0, difficulty:"easy", rationale:"Correct: (A) The Hawthorne effect: participants modify their behavior simply because they are being studied/observed, regardless of the specific experimental conditions. Named after Western Electric's Hawthorne Works studies.\n\nWhy others are wrong:\n(B) Experimenter bias involves the RESEARCHER influencing results unconsciously, not participant reactivity\n(C) Natural maturation is developmental change over time, not reactivity to being studied\n(D) Testing effects involve practice/familiarity with the test instrument itself"},
        {domainId:7, q:"Cronbach's alpha measures:", options:["Strict test-retest reliability formally measuring explicit temporal stability over time","Internal consistency reliability — the degree to which items measure the same construct","Specific standard inter-rater reliability strictly calculating exact observer agreement","Robust defined predictive concurrent criterion validity anticipating future exact outcomes"], answer:1, difficulty:"easy", rationale:"Correct: (B) Cronbach's α: the average inter-item correlation across all possible split-half combinations. Values range from 0-1; ≥ .70 is generally acceptable, ≥ .80 is good. Measures how well items 'hang together.'\n\nWhy others are wrong:\n(A) Test-retest = stability over time (measured by administering twice and correlating)\n(C) Inter-rater reliability = agreement between raters (measured by Cohen's kappa or ICC)\n(D) Predictive validity = test's ability to predict future outcomes (measured by correlation with criterion)"},
        {domainId:7, q:"Ecological validity in research refers to:", options:["Specifically thoroughly investigating highly complex natural diverse biological ecosystems","The extent to which research findings generalize to real-world settings and everyday behavior","Strictly exclusively evaluating explicitly and profoundly isolated robust internal validity","Rigorously confirming appropriately precise explicit direct statistical conclusion validity"], answer:1, difficulty:"easy", rationale:"Correct: (B) Ecological validity: whether findings obtained in the lab (or other research settings) apply to natural, everyday environments and behaviors. High ecological validity = real-world relevance.\n\nWhy others are wrong:\n(A) 'Ecological' refers to natural/real-world settings, not biological ecosystems\n(C) Ecological validity is a component of EXTERNAL validity, not internal validity\n(D) Statistical conclusion validity concerns the appropriate use of statistics, a different validity type"},

        // ===== Domain 8: Ethics (5) =====
        {domainId:8, q:"A psychologist who has a sexual relationship with a current client is:", options:["Violating precise therapeutic professional clinical ethics explicitly if fully consented","Always violating Standard 10.05 — sexual intimacies with current clients are prohibited","Only objectively formally exclusively in complete violation if the therapist initiated","Absolutely not explicitly empirically formally in violation if the therapy is going well"], answer:1, difficulty:"easy", rationale:"Correct: (B) Standard 10.05: Sexual intimacies with current therapy clients are prohibited. Period. No exceptions for consent, therapeutic progress, client initiation, or mutual attraction. This is an absolute prohibition.\n\nWhy others are wrong:\n(A) Client consent does NOT make sexual contact ethical — the power differential makes true consent questionable\n(C) Regardless of who initiated, the therapist bears professional responsibility\n(D) Quality of therapy is irrelevant — the prohibition is absolute"},
        {domainId:8, q:"Record-keeping requirements for psychologists typically state that:", options:["Records can be definitively and perfectly thoroughly destroyed immediately strictly post-session","Records must be kept for a minimum defined period (e.g. 7 years) per APA guidelines and state law","Specific standard structured formal precise routine diagnostic clinical firm records are optional","Absolutely no distinctly unique individual defined direct identifying information should be kept"], answer:1, difficulty:"medium", rationale:"Correct: (B) APA Guidelines: maintain records for at least 7 years after last service (or 3 years after a minor reaches majority, whichever is longer). State laws vary and must be followed. Records document care and protect both client and psychologist.\n\nWhy others are wrong:\n(A) Immediate destruction violates record-keeping standards and could be considered destruction of evidence\n(C) Record-keeping is a professional REQUIREMENT, not optional\n(D) Records must contain identifying information to be clinically useful and legally compliant"},
        {domainId:8, q:"Psychologists must report their own ethical violations or impairment because:", options:["Formal systematic ethical reporting of specific personal subjective true impairment remains fully optional","Specific standards require explicitly reporting actual violations alongside addressing personal impairment","The strict extremely formal continuous clinical explicit professional defining mandate binds only students","Proactive independent objective individual clinical formal systematic ethical reporting is entirely optional"], answer:1, difficulty:"medium", rationale:"Correct: (B) Standard 1.05: psychologists take reasonable steps to address ethical violations they become aware of. Standard 2.06: psychologists refrain from practice when personal problems may impair their competence. Both obligations apply.\n\nWhy others are wrong:\n(A) Self-reporting and addressing impairment is a professional OBLIGATION\n(C) Standards apply to ALL psychologists, not just students\n(D) The obligation exists regardless of whether anyone else has reported — it's proactive"},
        {domainId:8, q:"Pro bono services are:", options:["Strictly distinctly mandatorily universally explicitly required for all professionals at all exact times","Encouraged by the APA Ethics Code as a contribution to the public good and broad societal responsibility","Strictly distinctly completely overwhelmingly specifically prohibited by all standard licensing exact boards","Strictly essentially exclusively uniquely fundamentally reserved only for academic graduate students merely"], answer:1, difficulty:"easy", rationale:"Correct: (B) Principle B (Fidelity and Responsibility): psychologists are encouraged to contribute a portion of their professional time for little or no compensation. Pro bono is encouraged but not absolutely required.\n\nWhy others are wrong:\n(A) Pro bono is encouraged but not mandated at all times\n(C) Pro bono is ENCOURAGED, not prohibited — licensing boards support community service\n(D) All licensed psychologists can provide pro bono services — it's not limited to trainees"},
        {domainId:8, q:"When psychologists provide services via telehealth, they must:", options:["Operate exactly identically parallel precisely smoothly doing strictly nothing different from formal in-person practice","Ensure telehealth competence, comply with all jurisdictions, address security, and obtain telehealth-specific consent","Specifically reliably carefully exactly safely exclusively use video platforms while explicitly never offering any phone","Systematically explicitly profoundly extensively broadly entirely carefully avoid providing any telehealth truly forever"], answer:1, difficulty:"medium", rationale:"Correct: (B) Telehealth requires: competence in technology-mediated service delivery, compliance with laws in both the psychologist's and client's jurisdictions, secure technology platforms, and informed consent addressing telehealth-specific risks.\n\nWhy others are wrong:\n(A) Telehealth involves unique considerations (technology, jurisdiction, security) that differ from in-person\n(C) Both video and phone can be appropriate depending on clinical needs and regulations\n(D) Telehealth is an accepted service delivery modality — avoidance isn't necessary or practical"}
    ];

    batch18.forEach(q => {
        const domain = EPPPData.domains.find(d => d.id === q.domainId);
        if (domain) {
            domain.questions.push({
                q: q.q, options: q.options, answer: q.answer,
                difficulty: q.difficulty, rationale: q.rationale,
                domainId: q.domainId, domainName: domain.name
            });
        }
    });

    console.log(`PasstheEPPP: Loaded ${batch18.length} additional questions (batch 18 — enhanced rationales).`);
})();
